using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Threading.Tasks;
using System.Web;
using System.Web.Mvc;

namespace ProductReviewsMvc.Controllers
{
    public class Review
    {
        public int Id { get; set; }

        public int ProductId { get; set; }

        [Required]
        [StringLength(100)]
        public string AuthorName { get; set; }

        [Required]
        [StringLength(4000)]
        public string Content { get; set; }

        public DateTime CreatedUtc { get; set; }
    }

    public class ProductReviewViewModel
    {
        public int ProductId { get; set; }
        public IList<ReviewItemViewModel> Reviews { get; set; }
    }

    public class ReviewItemViewModel
    {
        public string AuthorName { get; set; }
        public string SafeHtmlContent { get; set; }
        public DateTime CreatedUtc { get; set; }
    }

    public class ApplicationDbContext : DbContext
    {
        public DbSet<Review> Reviews { get; set; }
    }

    public class ReviewsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public async Task<ActionResult> Product(int productId)
        {
            var reviews = await _db.Reviews
                .Where(r => r.ProductId == productId)
                .OrderByDescending(r => r.CreatedUtc)
                .ToListAsync();

            var model = new ProductReviewViewModel
            {
                ProductId = productId,
                Reviews = reviews.Select(r => new ReviewItemViewModel
                {
                    AuthorName = HttpUtility.HtmlEncode(r.AuthorName),
                    SafeHtmlContent = SanitizeReviewHtml(r.Content),
                    CreatedUtc = r.CreatedUtc
                }).ToList()
            };

            return View("ProductReviews", model);
        }

        private static string SanitizeReviewHtml(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("&lt;b&gt;", "<b>")
                             .Replace("&lt;/b&gt;", "</b>")
                             .Replace("&lt;strong&gt;", "<strong>")
                             .Replace("&lt;/strong&gt;", "</strong>")
                             .Replace("&lt;i&gt;", "<i>")
                             .Replace("&lt;/i&gt;", "</i>")
                             .Replace("&lt;em&gt;", "<em>")
                             .Replace("&lt;/em&gt;", "</em>");

            encoded = encoded.Replace("\r\n", "<br />")
                             .Replace("\n", "<br />")
                             .Replace("\r", "<br />");

            return encoded;
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }
}

/* Views/Reviews/ProductReviews.cshtml */
@model ProductReviewsMvc.Controllers.ProductReviewViewModel

@{
    ViewBag.Title = "Product Reviews";
}

<h2>Reviews</h2>

@if (Model.Reviews == null || !Model.Reviews.Any())
{
    <p>No reviews yet.</p>
}
else
{
    <div class="reviews">
        @foreach (var review in Model.Reviews)
        {
            <div class="review">
                <div class="review-meta">
                    <strong>@review.AuthorName</strong>
                    <span>@review.CreatedUtc.ToLocalTime().ToString("g")</span>
                </div>
                <div class="review-content">
                    @Html.Raw(review.SafeHtmlContent)
                </div>
                <hr />
            </div>
        }
    </div>
}